import { useEffect, useState } from "react";
import "./styles/MyBooks.css";

function MyBooks() {
  const [borrowed, setBorrowed] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("borrowedBooks")) || [];
    setBorrowed(stored);
  }, []);

  const returnBook = (index) => {
    const updated = borrowed.filter((_, i) => i !== index);
    setBorrowed(updated);
    localStorage.setItem("borrowedBooks", JSON.stringify(updated));
  };

  return (
    <div className="mybooks-page">
      <h1 className="mybooks-title">📚 My Borrowed Books</h1>

      {borrowed.length === 0 ? (
        <p style={{ textAlign: "center", opacity: 0.7 }}>
          You have no borrowed books.
        </p>
      ) : (
        <div className="mybooks-grid">
          {borrowed.map((b, i) => (
            <div key={i} className="mybook-card">
              <img src={b.cover} alt={b.title} />
              <h3>{b.title}</h3>
              <p>{b.author}</p>
              <span className="due">Due: {b.due || "Not set"}</span>

              <button onClick={() => returnBook(i)}>
                Return Book
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyBooks;
